# Python ZAR formatting
def format_zar(amount_cents: int) -> str:
    amount = amount_cents / 100
    if amount < 0:
        return f'-R {abs(amount):,.2f}'
    return f'R {amount:,.2f}'

def parse_zar(amount_str: str) -> int:
    cleaned = amount_str.replace('R', '').replace(',', '').replace(' ', '').strip()
    return int(float(cleaned) * 100)

