# Python auth with bcrypt
from passlib.context import CryptContext
from jose import JWTError, jwt
from datetime import datetime, timedelta
import os

pwd_context = CryptContext(schemes=['bcrypt'], deprecated='auto')
SECRET_KEY = os.getenv('JWT_SECRET_KEY', 'change-me-in-production')
ALGORITHM = 'HS256'
ACCESS_TOKEN_EXPIRE = timedelta(minutes=30)
REFRESH_TOKEN_EXPIRE = timedelta(days=7)

def hash_password(password: str) -> str:
    return pwd_context.hash(password)

def verify_password(plain: str, hashed: str) -> bool:
    return pwd_context.verify(plain, hashed)

def create_access_token(data: dict) -> str:
    expire = datetime.utcnow() + ACCESS_TOKEN_EXPIRE
    return jwt.encode({**data, 'exp': expire, 'type': 'access'}, SECRET_KEY, algorithm=ALGORITHM)

def create_refresh_token(data: dict) -> str:
    expire = datetime.utcnow() + REFRESH_TOKEN_EXPIRE
    return jwt.encode({**data, 'exp': expire, 'type': 'refresh'}, SECRET_KEY, algorithm=ALGORITHM)

# Deal stage with auto-probability and commission
from enum import Enum

class DealStage(str, Enum):
    lead_qualified = 'lead_qualified'
    discovery = 'discovery'
    proposal = 'proposal'
    negotiation = 'negotiation'
    verbal_agreement = 'verbal_agreement'
    contract_sent = 'contract_sent'
    closed_won = 'closed_won'
    closed_lost = 'closed_lost'

STAGE_PROBABILITY = {
    DealStage.lead_qualified: 0.10,
    DealStage.discovery: 0.20,
    DealStage.proposal: 0.40,
    DealStage.negotiation: 0.60,
    DealStage.verbal_agreement: 0.80,
    DealStage.contract_sent: 0.90,
    DealStage.closed_won: 1.00,
    DealStage.closed_lost: 0.00,
}

def calculate_commission(deal_value_excl_vat: float) -> float:
    if deal_value_excl_vat <= 500_000:
        return round(deal_value_excl_vat * 0.05, 2)
    elif deal_value_excl_vat <= 2_000_000:
        return round(250_00 + (deal_value_excl_vat - 500_000) * 0.07, 2)
    else:
        return round(250_00 + 105_000 + (deal_value_excl_vat - 2_000_000) * 0.10, 2)
